namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Name { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public int DepartmentId { get; set; }
    public string CourseCode { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollments = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Pure and applied mathematics including analysis, algebra, and statistics." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Literature, writing, and linguistic studies." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Exploration of past events, societies, and civilizations." }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, DepartmentId = 1, CourseCode = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Covers variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She holds a PhD from MIT and has published extensively on programming pedagogy.", IsFeatured = true, DepartmentName = "Computer Science" },
            new() { Id = 2, DepartmentId = 1, CourseCode = "CS 201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques including sorting, searching, and dynamic programming.", Credits = 4, Schedule = "Tue/Thu 10:30 AM–12:00 PM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park is an expert in algorithm design and computational complexity. He previously worked at Google Research before joining academia.", IsFeatured = true, DepartmentName = "Computer Science" },
            new() { Id = 3, DepartmentId = 1, CourseCode = "CS 310", Title = "Database Systems", Description = "Relational database design, SQL, normalization, indexing, and an introduction to NoSQL databases.", Credits = 3, Schedule = "Mon/Wed 2:00–3:30 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez specializes in distributed database systems and has contributed to several open-source database projects.", IsFeatured = false, DepartmentName = "Computer Science" },
            new() { Id = 4, DepartmentId = 2, CourseCode = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions with applications to physics and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is a passionate educator who has received multiple teaching awards. His research focuses on differential equations.", IsFeatured = true, DepartmentName = "Mathematics" },
            new() { Id = 5, DepartmentId = 2, CourseCode = "MATH 220", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues, and applications.", Credits = 3, Schedule = "Tue/Thu 1:00–2:30 PM", InstructorName = "Dr. Emily White", InstructorBio = "Dr. White's research interests include numerical linear algebra and scientific computing.", IsFeatured = false, DepartmentName = "Mathematics" },
            new() { Id = 6, DepartmentId = 2, CourseCode = "MATH 301", Title = "Probability and Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is a passionate educator who has received multiple teaching awards. His research focuses on differential equations.", IsFeatured = false, DepartmentName = "Mathematics" },
            new() { Id = 7, DepartmentId = 3, CourseCode = "ENG 101", Title = "Composition and Rhetoric", Description = "Develop essential writing skills through essays, research papers, and critical analysis of texts.", Credits = 3, Schedule = "Tue/Thu 9:00–10:30 AM", InstructorName = "Prof. Alice Turner", InstructorBio = "Prof. Turner is an acclaimed author and writing instructor with over 20 years of teaching experience.", IsFeatured = false, DepartmentName = "English" },
            new() { Id = 8, DepartmentId = 3, CourseCode = "ENG 250", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present day, examining themes of identity and culture.", Credits = 3, Schedule = "Mon/Wed 3:00–4:30 PM", InstructorName = "Dr. Michael Brown", InstructorBio = "Dr. Brown is a specialist in 20th-century American literature and has authored three books on the subject.", IsFeatured = true, DepartmentName = "English" },
            new() { Id = 9, DepartmentId = 4, CourseCode = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly laboratory sessions.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Lab Thu 2:00–4:00 PM", InstructorName = "Dr. Neil Patel", InstructorBio = "Dr. Patel is an experimental physicist whose research in optics has been published in Nature and Science.", IsFeatured = false, DepartmentName = "Physics" },
            new() { Id = 10, DepartmentId = 4, CourseCode = "PHYS 201", Title = "Electromagnetism", Description = "Electric and magnetic fields, Maxwell's equations, electromagnetic waves, and optics.", Credits = 4, Schedule = "Tue/Thu 10:00–11:30 AM + Lab Fri 2:00–4:00 PM", InstructorName = "Dr. Neil Patel", InstructorBio = "Dr. Patel is an experimental physicist whose research in optics has been published in Nature and Science.", IsFeatured = false, DepartmentName = "Physics" },
            new() { Id = 11, DepartmentId = 5, CourseCode = "HIST 101", Title = "World History to 1500", Description = "Survey of major civilizations, empires, and cultural developments from antiquity through the late medieval period.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:30 PM", InstructorName = "Dr. Karen Davis", InstructorBio = "Dr. Davis is a historian specializing in ancient Mediterranean civilizations with extensive archaeological fieldwork experience.", IsFeatured = false, DepartmentName = "History" },
            new() { Id = 12, DepartmentId = 5, CourseCode = "HIST 205", Title = "Modern European History", Description = "Europe from the Enlightenment to the present, covering revolutions, world wars, and the formation of the EU.", Credits = 3, Schedule = "Mon/Wed 10:00–11:30 AM", InstructorName = "Dr. Thomas Grant", InstructorBio = "Dr. Grant is an expert on 20th-century European political history and has served as a visiting fellow at Oxford.", IsFeatured = true, DepartmentName = "History" }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.ToLowerInvariant();
            query = query.Where(c =>
                c.Title.ToLowerInvariant().Contains(term) ||
                c.CourseCode.ToLowerInvariant().Contains(term) ||
                c.InstructorName.ToLowerInvariant().Contains(term) ||
                c.Description.ToLowerInvariant().Contains(term));
        }

        return query.ToList();
    }

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public void SubmitEnrollment(EnrollmentRequest request)
    {
        _enrollments.Add(request);
    }
}

